const body = msg.payload || {};
const event = body.event;

if (event === "endpoint.url_validation") {
    const plainToken = body?.payload?.plainToken;
    const secret = env.get("ZOOM_WEBHOOK_SECRET_TOKEN") || "";
    if (!plainToken || !secret) {
        msg.statusCode = 503;
        msg.headers = { "Content-Type": "application/json" };
        msg.payload = {
            error: "Missing plainToken or ZOOM_WEBHOOK_SECRET_TOKEN"
        };
        return [msg, null];
    }

    const encryptedToken = crypto
        .createHmac("sha256", secret)
        .update(plainToken)
        .digest("hex");

    msg.statusCode = 200;
    msg.headers = { "Content-Type": "application/json" };
    msg.payload = {
        plainToken,
        encryptedToken
    };
    return [msg, null];
}

const timestamp = msg.req?.headers?.["x-zm-request-timestamp"] || "";
const signature = msg.req?.headers?.["x-zm-signature"] || "";
const secret = env.get("ZOOM_WEBHOOK_SECRET_TOKEN") || "";
let signatureValid = false;
let expectedSignature = "";

if (timestamp && signature && secret) {
    const message = `v0:${timestamp}:${JSON.stringify(body)}`;
    const hash = crypto.createHmac("sha256", secret).update(message).digest("hex");
    expectedSignature = `v0=${hash}`;
    signatureValid = signature === expectedSignature;
}

const eventMsg = {
    payload: {
        received_at: new Date().toISOString(),
        event,
        signature_valid: signatureValid,
        expected_signature: expectedSignature,
        headers: {
            "x-zm-request-timestamp": timestamp,
            "x-zm-signature": signature
        },
        body
    }
};

msg.statusCode = 200;
msg.headers = { "Content-Type": "application/json" };
msg.payload = { ok: true };
return [msg, eventMsg];

const stream = (msg.req?.params?.stream || "").trim();
if (!/^[A-Za-z0-9._-]+$/.test(stream)) {
    msg.statusCode = 400;
    msg.headers = { "Content-Type": "application/json" };
    msg.payload = { error: "Invalid stream id" };
    return msg;
}
msg.statusCode = 200;
msg.headers = { "Content-Type": "text/html; charset=utf-8" };
msg.payload = `<!doctype html>
<html lang="en">
<head>
<meta charset="utf-8" />
<meta name="viewport" content="width=device-width, initial-scale=1" />
<title>Zoom Stream ${stream}</title>
<style>
body { font-family: Arial, sans-serif; background:#0f172a; color:#e2e8f0; margin:0; padding:24px; }
main { max-width: 960px; margin: 0 auto; }
video { width:100%; background:#000; border-radius:12px; }
a { color:#93c5fd; }
</style>
</head>
<body>
<main>
<h1>Zoom Stream: ${stream}</h1>
<p>Playlist: <a href="/hls/${stream}/index.m3u8">/hls/${stream}/index.m3u8</a></p>
<video controls autoplay playsinline src="/hls/${stream}/index.m3u8"></video>
</main>
</body>
</html>`;
return msg;

const stream = (msg.req?.params?.stream || "").trim();
if (!/^[A-Za-z0-9._-]+$/.test(stream)) {
    msg.statusCode = 400;
    msg.headers = { "Content-Type": "application/json" };
    msg.payload = { error: "Invalid stream id" };
    return [null, msg];
}
msg.url = `http://127.0.0.1/hls/${stream}/index.m3u8`;
msg.headers = { Host: "mondayzoom.sellsystems.agency" };
msg._reply_headers = {
    "Content-Type": "application/vnd.apple.mpegurl",
    "Cache-Control": "no-cache",
    "Access-Control-Allow-Origin": "*"
};
return [msg, null];

const stream = (msg.req?.params?.stream || "").trim();
const segment = (msg.req?.params?.segment || "").trim();
if (!/^[A-Za-z0-9._-]+$/.test(stream) || !/^[A-Za-z0-9._-]+\.ts$/.test(segment)) {
    msg.statusCode = 400;
    msg.headers = { "Content-Type": "application/json" };
    msg.payload = { error: "Invalid stream or segment" };
    return [null, msg];
}
msg.url = `http://127.0.0.1/hls/${stream}/${segment}`;
msg.headers = { Host: "mondayzoom.sellsystems.agency" };
msg._reply_headers = {
    "Content-Type": "video/mp2t",
    "Cache-Control": "no-cache",
    "Access-Control-Allow-Origin": "*"
};
return [msg, null];
